threads = [
{"threadId": "14c395a384122279", "messages": [
{"messageId": "14c395a384122279", "headers": {"From": "Tim Schwab <pyzaist@gmail.com>", "Date": "Fri, 20 Mar 2015 15:42:32 -0700", "Subject": "[opencog-dev] Building OpenCog"}, "body": "I installed Ubuntu 14.04 fresh. The install-dependencies-trusty script fails with unmet dependencies for libcheese-gtk23 and libclutter. Universe repositories are enabled."},
{"messageId": "14c396a87f74a8ba", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Fri, 20 Mar 2015 18:00:01 -0500", "Subject": "Re: [opencog-dev] Building OpenCog"}, "body": "After installing ubuntu, you should say apt-get update then apt-get upgrade. These errors have nothing to do with opencog. Try uninstalling gstreamer1.0-clutter or libcheese-gtk23 and then run apt-get -f a few times. I am guessing some archaic version of cheese is screwing things up. Last time I was bit, it was by nvidia."},
{"messageId": "14c3ad05a601c5ea", "headers": {"From": "Tim Schwab <pyzaist@gmail.com>", "Date": "Fri, 20 Mar 2015 22:31:13 -0700", "Subject": "Re: [opencog-dev] Building OpenCog"}, "body": "Yeah, I had done that as well. I did it again just to make sure, and got the same error message."},
{"messageId": "14c3ad748d49044e", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Sat, 21 Mar 2015 00:38:27 -0500", "Subject": "Re: [opencog-dev] Building OpenCog"}, "body": "Did you enable universe as the error message suggests? These errors only occur for a few rare reasons: a badly built package, or a package maintainer mistake. Try uninstalling the problematic packages."},
{"messageId": "14c3cf87e2d7344d", "headers": {"From": "Tim Schwab <pyzaist@gmail.com>", "Date": "Sat, 21 Mar 2015 08:34:17 -0700", "Subject": "Re: [opencog-dev] Building OpenCog"}, "body": "Thanks so much, I was able to download the dependencies and build it after I removed both of those."},
{"messageId": "14ce78f8d4f215b7", "headers": {"From": "Felix Velazquez <flxvlqz@gmail.com>", "Date": "Thu, 23 Apr 2015 11:34:45 -0700", "Subject": "Re: [opencog-dev] Building OpenCog"}, "body": "It also worked for me after installing the NVIDIA drivers for my graphics card, so I guess that is the right explanation."}
]},
{"threadId": "14c436ee2ce48b17", "messages": [
{"messageId": "14c436ee2ce48b17", "headers": {"From": "Prateek Saxena <prateeksaxena2809@gmail.com>", "Date": "Mon, 23 Mar 2015 03:11:20 +0530", "Subject": "[opencog-dev] GSoC 2015 Proposal for PLN Inference on extracted semantic relationships"}, "body": "Thanks for all your guidance in introducing me to opencog. I have begun writing my GSoC 2015 application for PLN inference on extracted semantic relationships. I need more information about specific tasks and expected timelines."},
{"messageId": "14c4dc9058748cd4", "headers": {"From": "Prateek Saxena <prateeksaxena2809@gmail.com>", "Date": "Wed, 25 Mar 2015 03:25:58 +0530", "Subject": "[opencog-dev] Re: GSoC 2015 Proposal for PLN Inference"}, "body": "I have been working on my proposal and am close to getting it finished. The sections I am working on are regarding specific tasks and timelines."},
{"messageId": "14c50190a62914d2", "headers": {"From": "Amen Belayneh <amenbelayneh@gmail.com>", "Date": "Wed, 25 Mar 2015 01:42:37 -0700", "Subject": "[opencog-dev] Re: GSoC 2015 Proposal for PLN Inference"}, "body": "The main tasks will involve porting the different rules and examples associated with them. It is hard to get a timeline for individual tasks. Make it up as you judge fit. Just submit your proposal on GSoC site and let us know here."},
{"messageId": "14c5322914d72f0e", "headers": {"From": "Prateek Saxena <prateeksaxena2809@gmail.com>", "Date": "Thu, 26 Mar 2015 04:21:54 +0530", "Subject": "Re: [opencog-dev] Re: GSoC 2015 Proposal for PLN Inference"}, "body": "I have submitted the first draft of my proposal on the GSoC website. Could you have a look at it?"},
{"messageId": "14c5aa984105d37e", "headers": {"From": "Amen Belayneh <amenbelayneh@gmail.com>", "Date": "Fri, 27 Mar 2015 09:56:38 +0000", "Subject": "Re: [opencog-dev] Re: GSoC 2015 Proposal for PLN Inference"}, "body": "Your proposal is clear, nothing much to be added, as far as I can tell. Good Luck."},
{"messageId": "14c5ab29b38aad22", "headers": {"From": "Prateek Saxena <prateeksaxena2809@gmail.com>", "Date": "Fri, 27 Mar 2015 15:36:34 +0530", "Subject": "Re: [opencog-dev] Re: GSoC 2015 Proposal for PLN Inference"}, "body": "Thank you for getting back so quickly."}
]},
{"threadId": "14bf254e9c15a350", "messages": [
{"messageId": "14bf254e9c15a350", "headers": {"From": "Arley Ristar <arley@ristar.me>", "Date": "Fri, 6 Mar 2015 19:36:11 -0800", "Subject": "[opencog-dev] Improved hBOA - GSOC 2015"}, "body": "I am a masters student in CS focused on intelligent agents and machine learning at UFPE Brazil. I am interested in the Improved hBOA idea for MOSES. Several questions about how hBOA compares to hill-climbing in this context."},
{"messageId": "14bf25edbed33560", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Sat, 7 Mar 2015 11:54:35 +0800", "Subject": "Re: [opencog-dev] Improved hBOA - GSOC 2015"}, "body": "In a MOSES context, hBOA underperformed hill-climbing and was removed from the current codebase. Given the same number of fitness evaluations as hillclimbing, it tended to come to worse answers. The problem was that in most practical contexts, there was not enough data for hBOA to mine sufficient meaningful dependency information. We are open to other algorithms. We encourage you to write a paper on your GSoC work if it generates new research results."},
{"messageId": "14c2513ab6eca93a", "headers": {"From": "Arley Ristar <arley@ristar.me>", "Date": "Mon, 16 Mar 2015 17:12:34 -0700", "Subject": "Re: [opencog-dev] Improved hBOA - GSOC 2015"}, "body": "If hill-climbing outperformed hBOA, I will change my focus to testing another algorithm. Have you considered using PSO or ABC to refine? Have you considered creating an interface to a C++ optimization library?"},
{"messageId": "14c30b5835358266", "headers": {"From": "Linas Vepstas <linasvepstas@gmail.com>", "Date": "Thu, 19 Mar 2015 01:25:21 -0500", "Subject": "Re: [opencog-dev] Improved hBOA - GSOC 2015"}, "body": "The number of knobs grows as expression trees become larger. The typical problem is to limit growth and aim at the most-likely trees. MOSES does really quite poorly in learning continuous expressions because it tries to learn constants one bit at a time. The total space becomes hopelessly large very quickly: if there are 500 knobs, then the total space is about 3^500."},
{"messageId": "14c30c0f129110e0", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Thu, 19 Mar 2015 14:38:10 +0800", "Subject": "Re: [opencog-dev] Improved hBOA - GSOC 2015"}, "body": "Using an interface to a C++ optimization library is not an obviously terrible idea. We have thought about it but not done it. Do you have some specific optimization algorithm or library in mind?"}
]},
{"threadId": "14be8c366052ec1d", "messages": [
{"messageId": "14be8c366052ec1d", "headers": {"From": "Kaivan Shah <kaivan29@tamu.edu>", "Date": "Tue, 3 Mar 2015 16:35:25 -0800", "Subject": "[opencog-dev] GSOC_2015_FLAG -- Haskell Bindings for OpenCog"}, "body": "I am a sophomore at Texas A&M University, interested in the Haskell bindings project. My competency in C++ and Haskell is intermediate."},
{"messageId": "14bea29fce8434ce", "headers": {"From": "Nil Geisweiller <ngeiswei@googlemail.com>", "Date": "Thu, 05 Mar 2015 14:39:53 +0100", "Subject": "Re: [opencog-dev] GSOC_2015_FLAG -- Haskell Bindings for OpenCog"}, "body": "You would need to study the AtomSpace and its API, drawing inspiration from existing binding languages like Scheme. You need to demonstrate in your proposal that you understand the task and sketch a step by step plan. It looks like I would be the main mentor, but Ben and Linas would help as well."},
{"messageId": "14bf927855b474bf", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Sun, 8 Mar 2015 19:31:27 +0800", "Subject": "Re: [opencog-dev] GSOC_2015_FLAG -- Haskell Bindings for OpenCog"}, "body": "I have looked over your example Haskell code, and it is reasonably clean and elegant. My sense is that making Haskell bindings to OpenCog might end up being a bit much for you. I think it might be a better fit to make a prototype exploring Haskell-based evolutionary learning of complex programmatic constructs using fold and GenProg, which could be inserted into MOSES as an alternative for what happens inside a deme."},
{"messageId": "14bfe237d296e4a9", "headers": {"From": "Nil Geisweiller <ngeiswei@googlemail.com>", "Date": "Mon, 09 Mar 2015 11:45:09 +0100", "Subject": "Re: [opencog-dev] GSOC_2015_FLAG -- Haskell Bindings for OpenCog"}, "body": "A full binding is probably too big indeed, but we could aim at a simplified binding, it would still be useful. Ben, if you think you can handle most of the mentoring for the GenProg project, I am happy to help for the MOSES binding part."},
{"messageId": "14bfe27802c1f765", "headers": {"From": "Ben Goertzel <ben@goertzel.org>", "Date": "Mon, 9 Mar 2015 18:49:33 +0800", "Subject": "Re: [opencog-dev] GSOC_2015_FLAG -- Haskell Bindings for OpenCog"}, "body": "I can personally mentor a GenProg project, but probably not a Haskell-bindings project. I think you would be better for the latter."}
]}
]

